// Collapse the up-to-50 history rows into a single text blob for the model.
const rows = $input.all();
const lines = [];
for (const r of rows) {
  const m = r.json.message;
  let content = '';
  try {
    const obj = (typeof m === 'string') ? JSON.parse(m) : m;
    content = (obj && obj.data && obj.data.content) ? obj.data.content : '';
  } catch (e) { content = String(m || ''); }
  if (content) { lines.push(String(content)); }
}
return [{ json: { transcript: lines.join('\n') } }];

// Parse the model's JSON robustly; fall back to a safe default profile.
const raw = String($input.first().json.text != null ? $input.first().json.text : ($input.first().json.output != null ? $input.first().json.output : ''));
const fallback = { language_primary: 'he', formality: 'casual', avg_reply_length_words: 35, emoji_use: 'moderate', humor: 'dry', technical_depth: 'high', address_form: 'second person, informal', anti_patterns: ['verbose preambles', 'corporate hedging'] };
let profile = fallback;
try {
  const m = raw.match(/\{[\s\S]*\}/);
  if (m) {
    const parsed = JSON.parse(m[0]);
    if (parsed && typeof parsed === 'object') { profile = parsed; }
  }
} catch (e) { profile = fallback; }
const profile_sql = JSON.stringify(profile || {}).split("'").join("''");
return [{ json: { profile: profile, profile_sql: profile_sql } }];

